// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Blueprint_Missing_Message (Full Dynamic)
// DESC: Recupero nomi umani dal catalogo e navigazione dinamica
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;

// 1. Recupero basi dati
const catalog = item.service_catalog_setup || {};
const userReq = item.user_request || {};
const owner = item.owner_data || {};

const skuId = userReq.ghost_id;
const categoryId = userReq.category_id;

// 2. Lookup Intelligente nel Catalogo
let skuName = skuId; // Fallback
let categoryName = "Area selezionata"; // Fallback
let macro = "sop"; // Default

if (catalog.categories && Array.isArray(catalog.categories)) {
    // Troviamo la categoria corretta
    const currentCategory = catalog.categories.find(cat => cat.callback_data === categoryId);

    if (currentCategory) {
        // Estraiamo il nome della categoria (pulito)
        categoryName = currentCategory.short_name || currentCategory.name.replace(/\[.*?\]/g, '').trim();
        macro = (currentCategory.macrocategories || "SOP").toLowerCase();

        // Troviamo il nome della procedura specifica dentro le subcategories
        if (currentCategory.subcategories) {
            const currentProcedure = currentCategory.subcategories.find(sub => sub.callback_data === skuId);
            if (currentProcedure) {
                skuName = currentProcedure.short_name || currentProcedure.name;
            }
        }
    }
}

// 3. Costruzione messaggi localizzati
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const translations = {
  'it': {
    title: "🛠️ <b>CONFIGURAZIONE NECESSARIA</b>",
    msg: `La procedura <b>"${skuName}"</b> (nella categoria <i>${categoryName}</i>) non è ancora stata configurata.`,
    explanation: "Per renderla operativa su Telegram, dobbiamo attivare il suo 'Blueprint'. Potrai poi personalizzare ogni passaggio sulla dashboard SiteBoS.",
    btn_activate: "🚀 Attiva Procedura Ora",
    btn_back: `⬅️ Torna a ${categoryName}`
  },
  'en': {
    title: "🛠️ <b>CONFIGURATION REQUIRED</b>",
    msg: `The procedure <b>"${skuName}"</b> (under <i>${categoryName}</i>) has not been configured yet.`,
    explanation: "To make it operational on Telegram, we need to activate its 'Blueprint'. You can then customize each step on the SiteBoS dashboard.",
    btn_activate: "🚀 Activate Procedure Now",
    btn_back: `⬅️ Back to ${categoryName}`
  }
};

const t = translations[lang];

// 4. Payload per Telegram
const backCallback = `get_active_${macro}_${categoryId}`;
const chatId = item.chat_id || (item.body.callback_query && item.body.callback_query.message.chat.id);
const messageId = item.message_id || (item.body.callback_query && item.body.callback_query.message.message_id);

return [{
  json: {
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: chatId,
      message_id: messageId,
      text: `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n\n${t.msg}\n\n${t.explanation}`,
      parse_mode: "HTML",
      reply_markup: {
        inline_keyboard: [
          [{ text: t.btn_activate, callback_data: `confirm_blueprint_build_${skuId}` }],
          [{ text: t.btn_back, callback_data: backCallback }]
        ]
      }
    }
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Universal_Guided_Parser
// DESC: Estrae sop_id e step_id dal callback data di Telegram
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const cbData = item.body?.callback_query?.data || "";

// Inizializziamo l'oggetto di output (stessi nomi parametri WebApp)
let guidedContext = {
    sop_id: null,
    step_id: null,
    is_start: false,
    is_step: false
};

// Logica di estrazione (Pattern: guided_execution_sop_id=XXX&step_id=YYY)
if (cbData.startsWith('ge_')) {
    // Rimuoviamo il prefisso per pulire la stringa di query
    const queryString = cbData.replace('ge_', ''); // Resta: "sop_id=SOP_01&step_id=STEP_02"

    // Dividiamo i parametri usando '&' come separatore
    const params = queryString.split('&');

    params.forEach(param => {
        const [key, value] = param.split('=');
        if (key === 'si') guidedContext.sop_id = value;
        if (key === 'sti') guidedContext.step_id = value;
    });

    // Determiniamo lo stato del workflow
    if (guidedContext.sop_id && !guidedContext.step_id) {
        guidedContext.is_start = true; // È il primo clic sul pulsante "Certifica Passo-Passo"
    } else if (guidedContext.sop_id && guidedContext.step_id) {
        guidedContext.is_step = true;  // È un avanzamento della guida (clic su "Prossimo Step")
    }
}

// Restituiamo l'oggetto originale arricchito
return [{
    json: {
        ...item,
        guided_context: guidedContext
    }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Guided_Start_Message
// ═══════════════════════════════════════════════════════════════

const fItem = $input.first().json;

// 1. Recupero Dati Core
const bObj = fItem.Final_Blueprint || {};
const gCtx = fItem.guided_context || {};
const oInfo = fItem.owner_data || {};

const sopId = gCtx.sop_id;
const firstStepId = bObj.stages?.[0]?.steps?.[0]?.step_id || "ST01";
const vat = oInfo.vat_number || "IT00000000000";
const univoco = Math.random().toString(36).substring(2, 10).toUpperCase();

// 2. Analisi Dinamica del Blueprint
const stagesCount = bObj.stages?.length || 0;
const totalSteps = bObj.stages?.reduce((acc, stg) => acc + (stg.steps?.length || 0), 0) || 0;
const stageList = bObj.stages?.map((stg, i) => `  ${i+1}. <i>${stg.stage_name}</i>`).join("\n") || "";

// 3. Costruzione URL MiniApp
const baseUrl = fItem.urlMiniApp || "https://tuo-sito.it/"; 
const ash = `${vat}_${sopId}_${univoco}`;
const webAppUrl = `${baseUrl}supervisor_hub.html?ash=${ash}`;

// 4. Rilevamento Lingua
const rawL = (oInfo.lenguage || 'it').toLowerCase();
let L = rawL.includes('en') ? 'en' : 'it';

const t = {
  it: {
    title: "🚀 <b>ESECUZIONE GUIDATA</b>",
    subtitle: `Procedura: <b>\"${bObj.blueprint_name}\"</b>`,
    riepilogo: `📊 <b>PIANO OPERATIVO:</b>\nIl sistema ha strutturato il lavoro in <b>${stagesCount} fasi</b> e <b>${totalSteps} step</b> totali:\n${stageList}`,
    billing_title: "⛽ <b>LOGICA CREDITI:</b>",
    billing_body: "• <b>Verifica Manuale:</b> Gratis.\n• <b>Verifica AI:</b> 1 Credito*.",
    disclaimer: "<i>* Il costo della verifica AI può variare in base alla complessità dell'analisi richiesta.</i>",

    // AGGIUNTA SPIEGAZIONE MODALITÀ
    mode_title: "⚙️ <b>Scegli la modalità di lavoro:</b>",
    mode_chat: "• <b>In Chat:</b> Procedura consecutiva (non può essere interrotta).",
    mode_hub: "• <b>Hub:</b> Procedura asincrona (puoi fare pause e riprendere).",

    btn_start: "🚀 INIZIA ORA (In Chat)",
    btn_hub: "📱 APRI SUPERVISOR HUB (Flessibile)",
    btn_back: "⬅️ TORNA INDIETRO"
  },
  en: {
    title: "🚀 <b>GUIDED EXECUTION</b>",
    subtitle: `Procedure: <b>\"${bObj.blueprint_name}\"</b>`,
    riepilogo: `📊 <b>OPERATIONAL PLAN:</b>\nThe system has structured the work into <b>${stagesCount} stages</b> and <b>${totalSteps} steps</b> total:\n${stageList}`,
    billing_title: "⛽ <b>CREDITS LOGIC:</b>",
    billing_body: "• <b>Manual Verification:</b> Free.\n• <b>AI Verification:</b> 1 Credit*.",
    disclaimer: "<i>* AI verification cost may vary based on the complexity of the requested analysis.</i>",

    mode_title: "⚙️ <b>Choose your working mode:</b>",
    mode_chat: "• <b>In Chat:</b> Consecutive procedure (cannot be interrupted).",
    mode_hub: "• <b>Hub:</b> Asynchronous procedure (take breaks and resume).",

    btn_start: "🚀 START NOW (Chat)",
    btn_hub: "📱 OPEN SUPERVISOR HUB (Flexible)",
    btn_back: "⬅️ GO BACK"
  }
}[L];

// 5. Formattazione Testo Finale
const msgText = `
${t.title}
━━━━━━━━━━━━━━━━━━━━
${t.subtitle}

${t.riepilogo}

━━━━━━━━━━━━━━━━━━━━
${t.billing_title}
${t.billing_body}
${t.disclaimer}

━━━━━━━━━━━━━━━━━━━━
${t.mode_title}
${t.mode_chat}
${t.mode_hub}`;

// 6. Costruzione Pulsanti
const keyboard = [
  [{ text: t.btn_start, callback_data: `ge_si=${sopId}&ei=${univoco}&sti=${firstStepId}` }],
  [{ text: t.btn_hub, web_app: { url: webAppUrl } }],
  [{ text: t.btn_back, callback_data: `get_active_sop_${sopId}` }]
];

return [{
  json: {
    ...fItem,
    exec_id: univoco,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: fItem.body.callback_query.message.chat.id,
      message_id: fItem.body.callback_query.message.message_id,
      text: msgText,
      parse_mode: "HTML",
      reply_markup: { inline_keyboard: keyboard }
    }
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Guided_Step_Execution (v4.4 - FINAL STABLE)
// DESC: Rich UI + Tracking ID + Tracking Report (Contextual)
// ═══════════════════════════════════════════════════════════════

const fItem = $input.first().json;

// 1. ESTRAZIONE PARAMETRI (ge_si, ei, sti)
const cbData = fItem.body?.callback_query?.data || "";
const getParam = (q, p) => {
    const m = q.match(new RegExp(`[?&]${p}=([^&]+)|${p}=([^&]+)`));
    return m ? (m[1] || m[2]) : null;
};

const sopId = getParam(cbData, 'ge_si') || getParam(cbData, 'si');
const execId = getParam(cbData, 'ei');
const stepId = getParam(cbData, 'sti');
const mId = fItem.body?.callback_query?.message?.message_id || fItem.message_id;
const operator = fItem.body?.callback_query?.from || {};

if (!execId) throw new Error("ID Sessione (ei) mancante.");

// 2. DATI CORE
const bObj = fItem.Final_Blueprint || {};
const oInfo = fItem.owner_data || {};
const vat = oInfo.vat_number || "IT00000000000";

// Recupero la base URL dalla variabile dinamica
const baseUrl = fItem.urlMiniApp; 

// --- LA CHIAVE UNIPOTENTE (Ripristinata) ---
const tracking_report_id = `${vat}_${sopId}_${execId}`;

// 3. COSTRUZIONE SEQUENZA STEP
let allSteps = [];
bObj.stages.forEach((stg, sIndex) => {
    stg.steps.forEach(stp => {
        allSteps.push({ 
            ...stp, 
            stageName: stg.stage_name, 
            stageDesc: stg.description,
            stageNum: sIndex + 1
        });
    });
});

const currentIdx = allSteps.findIndex(s => s.step_id === stepId);
const currentStep = allSteps[currentIdx];
const nextStep = allSteps[currentIdx + 1];

if (!currentStep) throw new Error(`Step ${stepId} non trovato.`);

// 4. LOGICA TRACKING REPORT CONTESTUALE (Inizializzazione vs Avanzamento)
let tracking_report = {
    report_id: tracking_report_id,
    exec_id: execId,
    sop_id: sopId,
    vat: vat,
    timestamp: new Date().toISOString()
};

if (currentIdx === 0) {
    // Caso A: Primo Step (Apertura Istanza)
    tracking_report.event_type = "INSTANCE_OPEN";
    tracking_report.status = "STARTED";
    tracking_report.operator_start = {
        chat_id: operator.id,
        full_name: `${operator.first_name || ""} ${operator.last_name || ""}`.trim()
    };
} else {
    // Caso B: Step Successivi (Tracciamento Step Precedente)
    const prevStep = allSteps[currentIdx - 1];
    tracking_report.event_type = "STEP_COMPLETED";
    tracking_report.status = "IN_PROGRESS";
    tracking_report.completed_step = {
        id: prevStep.step_id,
        name: prevStep.step_name,
        method: "SELF_MANUAL",
        operator_chat_id: operator.id
    };
}

// 5. LOGICA CALLBACK "AUTOCERTIFICA"
const manualCallback = nextStep 
    ? `ge_si=${sopId}&ei=${execId}&sti=${nextStep.step_id}` 
    : `ge_close_${tracking_report_id}`;

// 6. METADATI UI
const estTime = currentStep.estimated_time_minutes ? `${currentStep.estimated_time_minutes} min` : "N/D";
const reqSkills = currentStep.resources_needed?.labor?.required_skill_tags?.join(", ") || "Operatore Base";
const evType = (currentStep.quality_check?.evidence_type || "VISION").toUpperCase();
const evIcon = evType === "VISION" ? "📸" : (evType === "FILE" ? "📄" : (evType === "TEXT" ? "📝" : "✔️"));

// 7. LOCALIZZAZIONE
const L = (oInfo.lenguage || 'it').toLowerCase().includes('en') ? 'en' : 'it';
const t = {
    it: {
        procedure: "📂 PROCEDURA:",
        stage: "📍 FASE ATTUALE:",
        stepInfo: "⚙️ DETTAGLI STEP:",
        time: "⏱️ Tempo Est.:",
        skill: "👤 Skill:",
        instr: "📖 ISTRUZIONI OPERATIVE:",
        check: "✅ CRITERI DI VALIDAZIONE:",
        btn_man: "✍️ Autocertifica",
        btn_ai: `${evIcon} Certificazione AI`
    },
    en: {
        procedure: "📂 PROCEDURE:",
        stage: "📍 CURRENT STAGE:",
        stepInfo: "⚙️ STEP DETAILS:",
        time: "⏱️ Est. Time:",
        skill: "👤 Skill:",
        instr: "📖 OPERATIONAL INSTRUCTIONS:",
        check: "✅ VALIDATION CRITERIA:",
        btn_man: "✍️ Self-Certify",
        btn_ai: `${evIcon} AI Certification`
    }
}[L];

// 8. COSTRUZIONE MESSAGGIO TELEGRAM
const msgText = `
<b>[STEP ${currentIdx + 1} di ${allSteps.length}]</b>
━━━━━━━━━━━━━━━━━━━━
${t.procedure}
<b>${bObj.blueprint_name}</b>

${t.stage}
<b>${currentStep.stageNum}. ${currentStep.stageName}</b>
<i>${currentStep.stageDesc}</i>

━━━━━━━━━━━━━━━━━━━━
${t.stepInfo}
<b>${currentStep.step_name}</b>
${t.time} <code>${estTime}</code> | ${t.skill} <code>${reqSkills}</code>

${t.instr}
${currentStep.instructions}

${t.check}
• <i>${currentStep.quality_check.check_description}</i>
• <b>Target:</b> ${currentStep.quality_check.acceptance_criteria}

━━━━━━━━━━━━━━━━━━━━
👤 Operatore: <b>${operator.first_name} ${operator.last_name || ""}</b>
🆔 Sessione: <code>${execId}</code>`;

// 9. URL WEBAPP (Rimosso vat e chat_id, integrato baseUrl)
const webAppUrl = `${baseUrl}certificator.html?sop_id=${sopId}&step_id=${currentStep.step_id}&message_id=${mId}&evidence_type=${evType}&ei=${execId}&SBS=true`;

const keyboard = [[
    { text: t.btn_man, callback_data: manualCallback },
    { text: t.btn_ai, web_app: { url: webAppUrl } }
]];

// 10. OUTPUT FINALE (TUTTO INCLUSO)
return [{
  json: {
    ...fItem,
    tracking_report: tracking_report,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: oInfo.chat_id,
      message_id: mId,
      text: msgText,
      parse_mode: "HTML",
      reply_markup: { inline_keyboard: keyboard }
    }
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Extract_Tracking_And_SOP_On_Close
// DESC: Estrae tracking_report_id e sop_id dal callback ge_close_
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const cbData = item.body?.callback_query?.data || "";

// Inizializziamo l'oggetto richiesto
let guided_context = {
    tracking_report_id: null,
    sop_id: null,
    exec_id: null
};

if (cbData.startsWith('ge_close_')) {
    // 1. Estraiamo il tracking_report_id (tutto ciò che segue il prefisso)
    const fullId = cbData.replace('ge_close_', '');
    guided_context.tracking_report_id = fullId;

    // 2. Estraiamo il SOP_ID (lo SKU)
    // Struttura: VAT_PREFIX_SKUID_EXECID (es. IT..._SVC_NC0H4YN7_QSB8VHG0)
    const parts = fullId.split('_');

    // In base alla tua struttura: 
    // parts[0] = VAT
    // parts[1] = Prefisso SKU (SVC, SOP, PRO)
    // parts[2] = ID numerico SKU
    // parts[3] = Univoco Sessione
    if (parts.length >= 3) {
        guided_context.sop_id = `${parts[1]}_${parts[2]}`; // Ricostruisce: SVC_NC0H4YN7
        guided_context.exec_id = parts[parts.length - 1]; // L'univoco finale
    }
}

// Restituiamo l'item arricchito
return [{
    json: {
        ...item,
        guided_context: guided_context
    }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Final_JSON_Certification_Document
// DESC: Genera il documento unico JSON includendo l'orario di avvio
// ═══════════════════════════════════════════════════════════════

const fItem = $input.first().json;

// 1. RECUPERO DATI CORE
const bObj = fItem.Final_Blueprint || {};
const oInfo = fItem.owner_data || {};
const gCtx = fItem.guided_context || {};
const history = fItem.Cert_Step || []; 

const sopId = gCtx.sop_id;
const execId = gCtx.exec_id;
const vat = oInfo.vat_number;

// 2. ESTRAZIONE ORARIO DI INIZIO (Dall'evento INSTANCE_OPEN al cert_step 0)
const startData = history.length > 0 ? history[0].kwargs : {};
const startAt = startData.timestamp || new Date().toISOString(); 

// 3. COSTRUZIONE LOG DI ESECUZIONE (Audit Trail)
let execution_log = [];

// A. Trasformiamo la history (saltando il primo che è l'apertura) in step
history.forEach((msg) => {
    const k = msg.kwargs || {};
    if (k.event_type === "STEP_COMPLETED") {
        execution_log.push({
            step_id: k.completed_step.id,
            step_name: k.completed_step.name,
            method: k.completed_step.method,
            timestamp: k.timestamp
        });
    }
});

// B. INIEZIONE ULTIMO STEP (Chiusura)
const lastStage = bObj.stages[bObj.stages.length - 1];
const lastStep = lastStage.steps[lastStage.steps.length - 1];
const closedAt = new Date().toISOString();

execution_log.push({
    step_id: lastStep.step_id,
    step_name: lastStep.step_name,
    method: "SELF_MANUAL_CLOSE",
    timestamp: closedAt
});

// 4. GENERAZIONE DOCUMENTO UNICO PER MONGODB
const final_certification_doc = {
    document_type: "CERTIFICATION_RECORD",
    version: "1.0",
    certification_id: gCtx.tracking_report_id,
    execution_id: execId,
    sop_id: sopId,
    company_info: {
        vat: vat,
        operator_chat_id: oInfo.chat_id
    },
    blueprint_info: {
        name: bObj.blueprint_name,
        description: bObj.blueprint_description
    },
    status: "COMPLETED",
    timing: {
        started_at: startAt,
        closed_at: closedAt,
        // Calcolo rapido durata in minuti
        duration_minutes: Math.round((new Date(closedAt) - new Date(startAt)) / 60000)
    },
    total_steps_executed: execution_log.length,
    audit_trail: execution_log
};

// 5. PREPARAZIONE MESSAGGIO TELEGRAM
const L = (oInfo.lenguage || 'it').toLowerCase().includes('en') ? 'en' : 'it';
const t = {
    it: {
        title: "📜 <b>CERTIFICATO EMESSO</b>",
        body: `Procedura: <b>"${bObj.blueprint_name}"</b>`,
        start: "🏁 Inizio:",
        end: "✅ Fine:",
        btn: "⬅️ Torna alla Procedura"
    },
    en: {
        title: "📜 <b>CERTIFICATE ISSUED</b>",
        body: `Procedure: <b>"${bObj.blueprint_name}"</b>`,
        start: "🏁 Started:",
        end: "✅ Completed:",
        btn: "⬅️ Back to Procedure"
    }
}[L];

// Formattazione orari per il messaggio
const fmtTime = (iso) => new Date(iso).toLocaleTimeString(L === 'it' ? 'it-IT' : 'en-US', { hour: '2-digit', minute: '2-digit' });

const msgText = `
${t.title}
━━━━━━━━━━━━━━━━━━━━
${t.body}

🆔 Sessione: <code>${execId}</code>
${t.start} <code>${fmtTime(startAt)}</code>
${t.end} <code>${fmtTime(closedAt)}</code>

📊 Totale Step: <b>${execution_log.length}</b>
━━━━━━━━━━━━━━━━━━━━
🛡️ <i>Documento archiviato correttamente.</i>`;

// 6. OUTPUT FINALE
return [{
  json: {
    ...fItem,
    final_certification_doc: final_certification_doc,
    telegramApiPayload: {
      method: "editMessageText",
      chat_id: oInfo.chat_id,
      message_id: fItem.body?.callback_query?.message?.message_id || fItem.message_id,
      text: msgText,
      parse_mode: "HTML",
      reply_markup: {
        inline_keyboard: [[
            { text: t.btn, callback_data: `get_active_sop_${sopId}` }
        ]]
      }
    }
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Manager_Executive_Report_v4
// DESC: Dashboard Executive con terminologia tecnica e logica SiteBoS
// ═══════════════════════════════════════════════════════════════

const input = $input.first().json;

// 1. RECUPERO DATI CORE
const doc = input.final_certification_doc || {};
const owner = input.owner_data || {};
const bObj = input.Final_Blueprint || {};

// --- LOGICA DI CATEGORIZZAZIONE FERREA ---
const name = (doc.blueprint_info.name || "").toUpperCase();
const sku = (doc.sop_id || "").toUpperCase();

let typeLabel = "DOCUMENTO";
let typeIcon = "📄";

if (name.includes("[SOP]") || sku.startsWith("SOP_")) {
    typeLabel = "[SOP] PROCEDURA OPERATIVA";
    typeIcon = "📋";
} else if (name.includes("[SER]") || sku.startsWith("SER_") || sku.startsWith("SVC_")) {
    typeLabel = "[SER] SERVIZIO";
    typeIcon = "🛠️";
} else if (name.includes("[PRO]") || sku.startsWith("PRO_") || sku.startsWith("PRD_")) {
    typeLabel = "[PRO] PRODOTTO";
    typeIcon = "📦";
}

// 2. ANALISI METRICHE KPI
const totalSteps = doc.total_steps_executed;
const aiSteps = doc.audit_trail.filter(s => s.method.includes("AI")).length;
const healthScore = Math.round((aiSteps / totalSteps) * 100);
const healthBar = "🟩".repeat(Math.floor(healthScore/10)) + "⬜".repeat(10 - Math.floor(healthScore/10));

const actualTime = doc.timing.duration_minutes;
const estimatedTime = bObj.summary?.estimated_total_time_minutes || 0;
const timePerformance = actualTime <= estimatedTime ? "🟢 OTTIMALE" : "🔴 OVER-TIME";

// 3. RICOSTRUZIONE LOG EVENTI
let auditTrailHtml = "";
doc.audit_trail.forEach((step) => {
    const time = new Date(step.timestamp).toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' });
    const methodIcon = step.method.includes("AI") ? "🤖" : "✍️";
    auditTrailHtml += ` ├ <code>${time}</code> ${methodIcon} ${step.step_name}\n`;
});

// 4. COSTRUZIONE EXECUTIVE DASHBOARD (HTML)
const reportMessage = `
🏛️ <b>SITEBOS - EXECUTIVE AUDIT REPORT</b>
━━━━━━━━━━━━━━━━━━━━
🏷️ <b>CATEGORIA:</b> <code>${typeLabel}</code>
📝 <b>ATTIVITÀ:</b> <b>${doc.blueprint_info.name}</b>
🆔 <b>SESSIONE:</b> <code>${doc.execution_id}</code>

🎯 <b>OBIETTIVO STRATEGICO</b>
<i>"${doc.blueprint_info.description}"</i>

📊 <b>PERFORMANCE OPERATIVA</b>
────────────────────
⏱️ <b>Tempo Totale:</b> <code>${actualTime} min</code> (Target: ${estimatedTime}m)
📈 <b>Efficienza:</b> <code>${timePerformance}</code>
✅ <b>Integrità:</b> <code>${healthScore}% AI-Validated</code>
   ${healthBar}

📝 <b>LOG DI ESECUZIONE</b>
────────────────────
${auditTrailHtml}
 └ 🏁 <i>Sessione chiusa e certificata.</i>

━━━━━━━━━━━━━━━━━━━━
🔐 <b>INTEGRITÀ:</b> <code>VERIFIED</code>
🛡️ <b>ARCHIVIAZIONE:</b> <code>VAULT SECURE SITEBOS</code>`;

// 5. OUTPUT PAYLOAD
return [{
    json: {
        ...input,
        manager_report: {
            bot_token: owner.bot_key,
            chat_id: owner.chat_id,
            text: reportMessage,
            parse_mode: "HTML"
        }
    }
}];

